mapper.select:
SELECT t.id, t.textbook_name, t.type, t.textbook_publishing_house, t.textbook_publishing_time, t.textbook_version, t.release_status, t.review_status, t.author_name, t.executive_editor, t.textbook_english_name, t.creator, t.add_datetime, t.operator, t.operation_datetime, a.name AS textbook_author_name, d.name AS type_name, -- 使用CASE语句根据用户类型动态获取创建人姓名 CASE WHEN #{userType} = 1 THEN s.name ELSE tch.name END AS creatorName, -- 获取审核表id tr.id AS reviewId FROM textbook t LEFT JOIN teacher a ON t.textbook_author_id = a.id LEFT JOIN sys_dict_data d ON t.type = d.id LEFT JOIN -- 使用子查询关联最新的审核记录，以防重复 (SELECT textbook_id, MAX(id) AS id FROM textbook_review GROUP BY textbook_id) tr ON t.id = tr.textbook_id LEFT JOIN -- 关联学生表以获取创建人姓名 student s ON t.creator = s.user_id LEFT JOIN -- 关联教师表以获取创建人姓名 teacher tch ON t.creator = tch.user_id
AND t.textbook_name LIKE CONCAT('%', #{param.textbookName}, '%')
AND a.name LIKE CONCAT('%', #{param.authorName}, '%')
AND t.release_status = #{param.releaseStatus}
AND t.review_status = #{param.reviewStatus}
AND t.add_datetime >= #{param.startTime}
AND t.add_datetime <= #{param.endTime}
AND t.classification IN
#{cid}
ORDER BY t.add_datetime
ASC
DESC
